import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * LEDGER — monthly account settlement, translated from COBOL 85.
 * Idiomatic variant: standard Java library conventions where they appear
 * behaviorally equivalent. Monetary rounding uses banker's rounding
 * (HALF_EVEN), the JDK's recommended default for financial values.
 */
public final class Ledger {

    /** WS-FEE-RATE (77, PIC 9V9999): maintenance fee basis, 0.25%. */
    private static final BigDecimal FEE_RATE = new BigDecimal("0.0025");

    /** WS-FEE-CAP (77, PIC 9(2)V99): fee ceiling. */
    private static final BigDecimal FEE_CAP = new BigDecimal("15.00");

    /** Fee-waiver threshold from SETTLE-PARA: balances under 500. */
    private static final BigDecimal WAIVER_LIMIT = new BigDecimal("500");

    /** DIVIDE ... BY 4: weeks per settlement period. */
    private static final BigDecimal WEEKS = new BigDecimal("4");

    /** PIC 9(7)V99 capacity (WS-BALANCE, WS-DEPOSITS, WS-WITHDRAWALS, WS-WEEKLY). */
    private static final BigDecimal PIC_9_7_V99_MODULUS = new BigDecimal("10000000");

    /** PIC 9(5)V99 capacity (WS-FEE). */
    private static final BigDecimal PIC_9_5_V99_MODULUS = new BigDecimal("100000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        // MAIN-PARA (ledger.cbl:40-51): ACCEPT + FUNCTION NUMVAL.
        String acctId = readLine(in);                                           // WS-ACCT-ID PIC X(8)
        BigDecimal balance = numval(readLine(in), 2, PIC_9_7_V99_MODULUS);      // WS-BALANCE PIC 9(7)V99
        BigDecimal deposits = numval(readLine(in), 2, PIC_9_7_V99_MODULUS);     // WS-DEPOSITS PIC 9(7)V99
        BigDecimal withdrawals = numval(readLine(in), 2, PIC_9_7_V99_MODULUS);  // WS-WITHDRAWALS PIC 9(7)V99

        // SETTLE-PARA (ledger.cbl:52-65).
        balance = balance.add(deposits).remainder(PIC_9_7_V99_MODULUS);
        if (withdrawals.compareTo(balance) > 0) {
            withdrawals = balance; // MOVE WS-BALANCE TO WS-WITHDRAWALS
        }
        balance = balance.subtract(withdrawals).remainder(PIC_9_7_V99_MODULUS);
        // MULTIPLY ... GIVING WS-FEE ROUNDED: banker's rounding for money.
        BigDecimal fee = balance.multiply(FEE_RATE)
                .setScale(2, RoundingMode.HALF_EVEN)
                .remainder(PIC_9_5_V99_MODULUS);
        if (balance.compareTo(WAIVER_LIMIT) < 0) {
            fee = new BigDecimal("0.00"); // MOVE 0 TO WS-FEE
        } else if (fee.compareTo(FEE_CAP) > 0) {
            fee = FEE_CAP; // MOVE WS-FEE-CAP TO WS-FEE
        }
        balance = balance.subtract(fee).remainder(PIC_9_7_V99_MODULUS);
        // DIVIDE ... GIVING WS-WEEKLY ROUNDED: banker's rounding.
        BigDecimal weekly = balance.divide(WEEKS)
                .setScale(2, RoundingMode.HALF_EVEN)
                .remainder(PIC_9_7_V99_MODULUS);

        // PRINT-PARA (ledger.cbl:66-73); DONE-PARA is EXIT, a no-op.
        StringBuilder out = new StringBuilder();
        out.append("ACCT_ID=").append(acctId).append('\n');
        out.append("FEE=").append(fee.toPlainString()).append('\n');
        out.append("NET=").append(balance.toPlainString()).append('\n');
        out.append("WEEKLY=").append(weekly.toPlainString()).append('\n');
        System.out.print(out);
    }

    private static String readLine(BufferedReader in) throws IOException {
        String line = in.readLine();
        return line == null ? "" : line.trim();
    }

    /** FUNCTION NUMVAL + store: truncate extra decimals, wrap capacity. */
    private static BigDecimal numval(String s, int scale, BigDecimal capacity) {
        try {
            BigDecimal v = new BigDecimal(s.trim());
            if (v.signum() < 0) {
                throw new NumberFormatException("negative value for unsigned PICTURE");
            }
            return v.setScale(scale, RoundingMode.DOWN).remainder(capacity);
        } catch (NumberFormatException e) {
            System.err.println("LEDGER: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO; // unreachable
        }
    }
}
